const body = $input.first().json.body || $input.first().json;
if (!body.name || !body.contest) throw new Error('Missing name or contest');

const entry = {
  name:    String(body.name    || '').slice(0, 120),
  phone:   String(body.phone   || '').slice(0, 30),
  email:   String(body.email   || '').slice(0, 120),
  contest: String(body.contest || '').slice(0, 120),
  ts:      body.ts || new Date().toISOString()
};

const sd = $getWorkflowStaticData('global');
sd.entries = sd.entries || [];
sd.entries.push(entry);
if (sd.entries.length > 10000) sd.entries = sd.entries.slice(-10000);

return [{ json: { ok: true, total: sd.entries.length, entry } }];
